function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ node: v, cost });
    }

    // Use a priority queue to perform Dijkstra-like search
    const pq = new PriorityQueue((a, b) => b.cost - a.cost);
    pq.enqueue({ node: 0, minCost: Infinity, totalCost: 0 });

    // Keep track of the maximum minimum edge cost
    let maxMinCost = -1;

    while (!pq.isEmpty()) {
        const { node, minCost, totalCost } = pq.dequeue();

        // If we reached the destination node
        if (node === n - 1) {
            maxMinCost = Math.max(maxMinCost, minCost);
            continue;
        }

        // If the total cost exceeds k, skip this path
        if (totalCost > k) {
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const { node: neighbor, cost } of graph.get(node)) {
                // Check if the neighbor is online
                if (online[neighbor]) {
                    // Update the minimum edge cost along the path
                    const newMinCost = Math.min(minCost, cost);
                    // Update the total cost
                    const newTotalCost = totalCost + cost;

                    // If the new total cost is within k, add to the priority queue
                    if (newTotalCost <= k) {
                        pq.enqueue({ node: neighbor, minCost: newMinCost, totalCost: newTotalCost });
                    }
                }
            }
        }
    }

    return maxMinCost === -1 ? -1 : maxMinCost;
}

// Priority queue implementation
class PriorityQueue {
    constructor(compare) {
        this.compare = compare;
        this.items = [];
    }

    enqueue(item) {
        this.items.push(item);
        this.items.sort(this.compare);
    }

    dequeue() {
        return this.items.shift();
    }

    isEmpty() {
        return this.items.length === 0;
    }
}

