import java.util.*

fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val graph = HashMap<Int, List<Array<Long>>>().apply {
        for (edge in edges) {
            val u = edge[0].toInt()
            val v = edge[1].toInt()
            val cost = edge[2]
            if (!containsKey(u)) {
                put(u, mutableListOf())
            }
            put(u, mutableListOf()).add(intArrayOf(v, cost))
        }
    }

    // Use a priority queue to perform Dijkstra-like search
    val pq = PriorityQueue(compareByDescending({ it.minCost }, { it.totalCost }))
    pq.add(arrayOf(0, Long.MAX_VALUE, 0L))

    // Keep track of the maximum minimum edge cost
    var maxMinCost = -1L

    while (pq.isNotEmpty()) {
        val (node, minCost, totalCost) = pq.remove()

        // If we reached the destination node
        if (node == n - 1) {
            maxMinCost = maxOf(maxMinCost, minCost)
            continue
        }

        // If the total cost exceeds k, skip this path
        if (totalCost > k) {
            continue
        }

        // Explore neighbors
        graph.getOrDefault(node, emptyList()).forEach { edge ->
            val neighbor = edge[0]
            val cost = edge[1]

            // Check if the neighbor is online
            if (online[neighbor]) {
                // Update the minimum edge cost along the path
                val newMinCost = minOf(minCost, cost)
                // Update the total cost
                val newTotalCost = totalCost + cost

                // If the new total cost is within k, add to the priority queue
                if (newTotalCost <= k) {
                    pq.add(arrayOf(neighbor, newMinCost, newTotalCost))
                }
            }
        }
    }

    return if (maxMinCost == -1L) -1L else maxMinCost
}

class PriorityQueue<T>(private val compare: (T, T) -> Int) {
    private val items = mutableListOf<T>()

    fun add(item: T) {
        items.add(item)
        items.sortWith(compare)
    }

    fun remove(): T {
        return items.removeAt(0)
    }

    fun isNotEmpty(): Boolean {
        return items.isNotEmpty()
    }
}
